#include<bits/stdc++.h>
using namespace std;
int n,a[50050][6];
map<int,bitset<50050>> mp;
int main()
{
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=5;j++)
        {
            int x;
            scanf("%d",&x);
            a[i][j]=x;
            mp[x][i]=1;
        }
    }
    bitset<50050> s;
    long long ans=0;
    for(int i=1;i<=n;i++)
    {
        s=0;
        for(int j=1;j<=5;j++)
        {
            s|=mp[a[i][j]];
        }
        ans+=n-s.count();
    }
    ans/=2;
    printf("%lld",ans);
    return 0;
}
